// AUTO-GENERATED brand assets — SOKATF SARL logos embedded as base64 PNG.
// Regenerate with: node scripts/gen-brand.mjs (reads public/brand/*.png).
// Embedded (not read from disk) so PDF/Word generation works identically in
// the tsx seed/gen scripts, Next dev, and the bundled production server — no
// cwd/filesystem assumptions. Node-only (Buffer); never import from edge.

type LogoMeta = { b64: string; width: number; height: number };

export const LOGOS: Record<"colors" | "white" | "black", LogoMeta> = {
  colors: { width: 692, height: 93, b64: "" },
  white: { width: 683, height: 92, b64: "" },
  black: { width: 687, height: 89, b64: "" },
};

export type LogoVariant = keyof typeof LOGOS;

/** data: URI — for @react-pdf <Image src> and HTML <img src>. */
export const logoDataUri = (v: LogoVariant = "colors") =>
  `data:image/png;base64,${LOGOS[v].b64}`;

/** Raw PNG Buffer — for docx ImageRun. */
export const logoBuffer = (v: LogoVariant = "colors") =>
  Buffer.from(LOGOS[v].b64, "base64");

/** width / height, to preserve aspect ratio from a single dimension. */
export const logoAspect = (v: LogoVariant = "colors") =>
  LOGOS[v].width / LOGOS[v].height;
